// Parses the incoming multipart/form-data payload and performs robust integrity
// checks BEFORE any data leaves this n8n instance. 
//
// This upgraded version is highly flexible: it accepts nested, stringified JSON
// 'profile' objects OR standard flat form-data fields, and accommodates different
// binary file key names ('id_document' or 'file').

const items = $input.all();
const out = [];

for (const item of items) {
  const executionId = $execution.id;
  const receivedAt = new Date().toISOString();

  // 1. Resolve the Profile Data (handling nested JSON OR flat form fields)
  let profile = {};
  const rawProfile = item.json.body?.profile ?? item.json.profile;

  if (rawProfile) {
    try {
      profile = typeof rawProfile === 'string' ? JSON.parse(rawProfile) : rawProfile;
    } catch (err) {
      throw new Error(`Malformed 'profile' JSON payload: ${err.message}`);
    }
  } else {
    // Graceful fallback to flat form-data keys if no unified 'profile' object exists
    profile = {
      applicant_id: item.json.body?.applicant_id ?? item.json.applicant_id,
      email: item.json.body?.email ?? item.json.email,
      phone: item.json.body?.phone ?? item.json.phone,
      applicant_name: item.json.body?.applicant_name ?? item.json.applicant_name
    };
  }

  // 2. Validate Required Identification Fields
  if (!profile || !profile.applicant_id) {
    throw new Error("Validation Failed: Missing 'applicant_id' (must be provided either inside a 'profile' JSON object or as a flat form field).");
  }

  // 3. Resolve and Validate the Binary Payload (accepting 'id_document' or 'file')
  const binaryKeys = item.binary ? Object.keys(item.binary) : [];
  const targetBinaryKey = binaryKeys.find(key => key === 'id_document' || key === 'file');

  if (!targetBinaryKey) {
    throw new Error("Validation Failed: No valid binary document found. Please upload your ID file using the key 'id_document' or 'file'.");
  }

  // Normalize binary key to 'id_document' for downstream nodes
  const normalizedBinary = {};
  normalizedBinary['id_document'] = item.binary[targetBinaryKey];

  out.push({
    json: {
      execution_id: executionId,
      received_at: receivedAt,
      applicant_id: profile.applicant_id,
      applicant_name: profile.applicant_name || null,
      submitted_email: profile.email || null,
      submitted_phone: profile.phone || null
    },
    binary: normalizedBinary
  });
}

return out;

// Deterministic business-rule validation on the normalized OCR output.
// Three checks are enforced:
//   1. Age >= 18 (calculated precisely, accounting for month/day - not just year subtraction)
//   2. ID not expired
//   3. document_number was actually extracted (low-confidence scans can return blank fields)

const data = $input.item.json;

const dob = new Date(data.date_of_birth);
const expiry = new Date(data.expiry_date);
const today = new Date();

// Guard against unparsable dates returned by OCR (low-confidence extraction).
// Treat as a flagged case rather than letting `false > false` style bugs slip through.
if (isNaN(dob.getTime()) || isNaN(expiry.getTime())) {
  return {
    json: {
      ...data,
      applicant_age: null,
      kyc_passed: false,
      flag_reason: 'Unreadable date field(s) from OCR — manual review required'
    }
  };
}

let age = today.getFullYear() - dob.getFullYear();
const hadBirthdayThisYear =
  today.getMonth() > dob.getMonth() ||
  (today.getMonth() === dob.getMonth() && today.getDate() >= dob.getDate());
if (!hadBirthdayThisYear) age -= 1;

const isAdult = age >= 18;
const isValidID = expiry > today;
const hasDocumentNumber = !!data.document_number;

const kyc_passed = isAdult && isValidID && hasDocumentNumber;

let flag_reason = null;
if (!hasDocumentNumber) flag_reason = 'Missing document number (low OCR confidence)';
else if (!isAdult) flag_reason = 'Underage';
else if (!isValidID) flag_reason = 'Expired ID';

return {
  json: {
    ...data,
    applicant_age: age,
    kyc_passed,
    flag_reason
  }
};

