// Builds a structured technical-failure record when the Mindee OCR call
// fails outright (auth error, rate limit, timeout, corrupt image, etc.)
// This is a SYSTEM failure, not a KYC business-rule flag.

const err = $input.item.json.error || $input.item.json;
return {
  json: {
    execution_id: $('Parse & Validate Submission').item.json.execution_id,
    applicant_id: $('Parse & Validate Submission').item.json.applicant_id,
    failure_stage: 'OCR_EXTRACTION',
    error_message: (err && err.message) ? err.message : JSON.stringify(err).slice(0, 500),
    occurred_at: new Date().toISOString()
  }
};

